setTimeout(async () => {
    if (!this.isAdd) return;
    const maxRetries = 10;
    const interval = 500;
    for (let i = 0; i < maxRetries; i++) {
        const op = await this.onDropdownVisible('handling_no_type', true);
        if (op != null) break;
        await new Promise(resolve => setTimeout(resolve, interval));
    }
    function getDefaultItem(arr) {
        return arr?.find(item => item?.item?.is_default === 1);
    }
    const optionsData = this.getOptionData('handling_no_type') || [];
    const data = getDefaultItem(optionsData);
    if (data) {
        this.setData({ handling_no_type: data.value });
    }
}, 500);

